                            <p className="text-[9px] text-slate-500 dark:text-slate-400 pl-7">{t('upload.statementSubtitle')}</p>
                        </div>
                        <div className="flex-1 overflow-y-auto pr-1 custom-scrollbar z-10 space-y-1.5">
                            {banks.map(bank => {
