                                        <div className="flex items-center gap-2">
                                            {/* Botão de Lab específico do Admin */}
                                            {isAdmin && isThisUploaded && (
                                                <button 
                                                    onClick={() => openLabManually({ 
                                                        content: bankStatementFile!.content, 
                                                        fileName: bankStatementFile!.fileName, 
                                                        type: 'statement', 
                                                        id: bank.id,
