  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [message, setMessage] = useState<string | null>(null);

  const handleGoogleLogin = async () => {
    setLoading(true);
    setError(null);
    try {
        const { error } = await supabase.auth.signInWithOAuth({
            provider: 'google',
            options: {
                queryParams: {
                    access_type: 'offline',
                    prompt: 'consent',
                },
                redirectTo: window.location.origin
            },
        });
        if (error) throw error;
    } catch (error: any) {
        setError(error.message || 'Erro ao conectar com Google. Verifique se o provedor está habilitado no Supabase.');
        setLoading(false);
    }
  };

  const handleAuth = async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    setLoading(true);
    setError(null);
    setMessage(null);

    if (password.length < 6) {
        setError('A senha precisa ter no mínimo 6 caracteres.');
        setLoading(false);
        return;
    }

    try {
        if (isLogin) {
            // Timeout to prevent hanging indefinetely if network drops
            const authPromise = supabase.auth.signInWithPassword({
                email: email,
                password: password,
            });
            const timeoutPromise = new Promise<{data: any, error: any}>((_, reject) => 
                setTimeout(() => reject(new Error('Timeout na conexão. Verifique sua internet.')), 15000)
            );

            const { error } = await Promise.race([authPromise, timeoutPromise]);

            if (error) {
                setError(error.message);
            }
        } else {
            const { data, error } = await supabase.auth.signUp({
                email: email,
                password: password,
                options: {
                    data: {
                        full_name: name,
                    }
                }
            });

            if (error) {
                setError(error.message);
            } else {
                setMessage('Cadastro realizado! Verifique seu email para confirmação.');
            }
        }
    } catch (err: any) {
        console.error("Auth Error:", err);
